/**
 * @summary Get XP event history
 */
export const getListXpEventsUrl = (params?: ListXpEventsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/wallet/events?${stringifiedParams}`
    : `/api/wallet/events`;
};

export const listXpEvents = async (
  params?: ListXpEventsParams,
  options?: RequestInit,
): Promise<XpEvent[]> => {
  return customFetch<XpEvent[]>(getListXpEventsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListXpEventsQueryKey = (params?: ListXpEventsParams) => {
  return [`/api/wallet/events`, ...(params ? [params] : [])] as const;
};

export const getListXpEventsQueryOptions = <
  TData = Awaited<ReturnType<typeof listXpEvents>>,
  TError = ErrorType<unknown>,
>(
  params?: ListXpEventsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listXpEvents>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListXpEventsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listXpEvents>>> = ({
    signal,
  }) => listXpEvents(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listXpEvents>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListXpEventsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listXpEvents>>
>;
export type ListXpEventsQueryError = ErrorType<unknown>;

